#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
    int value;
    struct Node* next;
    struct Node* prev;
} Node;

void deleteNode(Node** head, int value) {
    Node* target = *head;
    while (target && target->value != value) target = target->next;
    if (!target) return; // should not happen per constraints
    Node* A = target->prev;
    Node* B = target->next;
    if (A) A->next = B;
    if (B) B->prev = A;
    if (target == *head) *head = B;
    free(target);
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n, x; scanf("%d %d", &n, &x);
        Node* head = NULL; Node* cur = NULL;
        for (int i = 0; i < n; ++i) {
            int v; scanf("%d", &v);
            Node* nd = (Node*)malloc(sizeof(Node));
            nd->value = v; nd->next = NULL; nd->prev = NULL;
            if (!head) { head = nd; cur = nd; }
            else { cur->next = nd; nd->prev = cur; cur = nd; }
        }
        deleteNode(&head, x);
        cur = head;
        while (cur) {
            printf("%d", cur->value);
            if (cur->next) printf(" ");
            cur = cur->next;
        }
        printf("\n");
        // free remaining nodes
        while (head) { Node* tmp = head; head = head->next; free(tmp); }
    }
    return 0;
}

