import java.io.*;
import java.util.*;

public class Main {
    static class Node {
        int value;
        Node next, prev;
        Node(int v) { value = v; }
    }

    static void deleteNode(Node[] headRef, int value) {
        Node target = headRef[0];
        while (target != null && target.value != value) target = target.next;
        if (target == null) return; // per constraints never happens
        Node A = target.prev;
        Node B = target.next;
        if (A != null) A.next = B;
        if (B != null) B.prev = A;
        if (target == headRef[0]) headRef[0] = B;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            st = new StringTokenizer(br.readLine());
            int n = Integer.parseInt(st.nextToken());
            int x = Integer.parseInt(st.nextToken());
            st = new StringTokenizer(br.readLine());
            Node head = null, cur = null;
            for (int i = 0; i < n; ++i) {
                int v = Integer.parseInt(st.nextToken());
                Node nd = new Node(v);
                if (head == null) { head = nd; cur = nd; }
                else { cur.next = nd; nd.prev = cur; cur = nd; }
            }
            Node[] headRef = new Node[]{head};
            deleteNode(headRef, x);
            cur = headRef[0];
            while (cur != null) {
                out.append(cur.value);
                if (cur.next != null) out.append(' ');
                cur = cur.next;
            }
            out.append('\n');
        }
        System.out.print(out.toString());
    }
}

