import sys

def delete_node(head, value):
    target = head
    while target and target.value != value:
        target = target.next
    if not target:
        return head  # per constraints never happens
    A = target.prev
    B = target.next
    if A:
        A.next = B
    if B:
        B.prev = A
    if target is head:
        head = B
    return head

class Node:
    __slots__ = ('value', 'next', 'prev')
    def __init__(self, v):
        self.value = v
        self.next = None
        self.prev = None

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        n = int(next(it)); x = int(next(it))
        head = None; cur = None
        for _ in range(n):
            v = int(next(it))
            nd = Node(v)
            if head is None:
                head = nd; cur = nd
            else:
                cur.next = nd
                nd.prev = cur
                cur = nd
        head = delete_node(head, x)
        vals = []
        cur = head
        while cur:
            vals.append(str(cur.value))
            cur = cur.next
        out_lines.append(' '.join(vals))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

